import type * as DMMF from '@prisma/dmmf'

/** Map a Prisma scalar type name to its TypeScript equivalent. */
export function prismaTypeToTypeScript(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Buffer'
    default:
      // Enum or composite type — referenced by name
      return prismaType
  }
}

function fieldTypeString(field: DMMF.Field): string {
  const base = prismaTypeToTypeScript(field.type)
  const typed = field.isList ? `${base}[]` : base
  return field.isRequired ? typed : `${typed} | null`
}

function isScalarOrEnum(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

function lowerFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Generate a TypeScript `enum` declaration from a DMMF enum. */
export function generateEnumType(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

/** Generate a TypeScript interface containing all scalar and enum fields of a model. */
export function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields.filter(isScalarOrEnum)
  const lines = fields.map((f) => `  ${f.name}: ${fieldTypeString(f)}`)
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Generate a `CreateInput` interface.
 *
 * Fields are optional when they have a default value, are auto-managed
 * (`@updatedAt`, generated, read-only), or are nullable.
 */
export function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isScalarOrEnum)
  const lines = fields.map((f) => {
    const optional = f.hasDefaultValue || f.isUpdatedAt || f.isGenerated || !f.isRequired || f.isReadOnly
    const marker = optional ? '?' : ''
    return `  ${f.name}${marker}: ${fieldTypeString(f)}`
  })
  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}`
}

/** Generate an `UpdateInput` interface where every field is optional and ID/read-only fields are excluded. */
export function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => isScalarOrEnum(f) && !f.isId && !f.isReadOnly)
  const lines = fields.map((f) => `  ${f.name}?: ${fieldTypeString(f)}`)
  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}`
}

/**
 * Generate a `WhereUniqueInput` interface used to identify a single record.
 *
 * Uses the `@id` field, or the compound `@@id` key fields. Falls back to the
 * first `@unique` field if no explicit primary key exists.
 */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  let keyFields: Array<{ name: string; type: string }>

  const idField = model.fields.find((f) => f.isId)

  if (idField) {
    keyFields = [{ name: idField.name, type: fieldTypeString(idField) }]
  } else if (model.primaryKey) {
    keyFields = model.primaryKey.fields.map((name) => {
      const f = model.fields.find((field) => field.name === name)!
      return { name, type: fieldTypeString(f) }
    })
  } else {
    const uniqueField = model.fields.find((f) => f.isUnique)
    keyFields = uniqueField ? [{ name: uniqueField.name, type: fieldTypeString(uniqueField) }] : []
  }

  const lines = keyFields.map((k) => `  ${k.name}: ${k.type}`)
  return `export interface ${model.name}WhereUniqueInput {\n${lines.join('\n')}\n}`
}

/** Generate the base REST client class with a generic `request` helper. */
export function generateBaseClient(): string {
  return `class BaseRestClient {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  protected async request<T>(method: string, path: string, body?: unknown): Promise<T> {
    const url = \`\${this.#baseUrl}\${path}\`
    const response = await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
    })
    if (!response.ok) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`)
    }
    return response.json() as Promise<T>
  }
}`
}

/** Generate a per-model client class with typed CRUD methods. */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const lower = lowerFirst(name)

  const idField = model.fields.find((f) => f.isId)
  const idAccessor = idField ? `where.${idField.name}` : 'where.id'

  return `export class ${name}Client extends BaseRestClient {
  async findMany(): Promise<${name}[]> {
    return this.request<${name}[]>('GET', '/${lower}')
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name}> {
    return this.request<${name}>('GET', \`/${lower}/\${${idAccessor}}\`)
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    return this.request<${name}>('POST', '/${lower}', data)
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    return this.request<${name}>('PATCH', \`/${lower}/\${${idAccessor}}\`, data)
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    return this.request<${name}>('DELETE', \`/${lower}/\${${idAccessor}}\`)
  }
}`
}

/** Generate the main `RestClient` class that aggregates per-model clients. */
export function generateMainClient(models: readonly DMMF.Model[]): string {
  const props = models.map((m) => `  ${lowerFirst(m.name)}: ${m.name}Client`).join('\n')
  const assignments = models.map((m) => `    this.${lowerFirst(m.name)} = new ${m.name}Client(baseUrl)`).join('\n')
  return `export class RestClient {
${props}

  constructor(baseUrl: string) {
${assignments}
  }
}`
}

