import fs from 'node:fs'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import {
  generateBaseClient,
  generateCreateInput,
  generateEnumType,
  generateMainClient,
  generateModelClient,
  generateModelInterface,
  generateUpdateInput,
  generateWhereUniqueInput,
} from './template'

export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('No output directory specified for prisma-generator-rest-client')
  }

  const code = generateRestClient(options.dmmf)

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), code, 'utf-8')
}

/** Generate a complete typed REST client from a DMMF document. */
export function generateRestClient(dmmf: DMMF.Document): string {
  const sections: string[] = []

  sections.push('// Generated by prisma-generator-rest-client — DO NOT EDIT.\n')

  for (const enumDef of dmmf.datamodel.enums) {
    sections.push(generateEnumType(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
    sections.push(generateWhereUniqueInput(model))
  }

  sections.push(generateBaseClient())

  for (const model of dmmf.datamodel.models) {
    sections.push(generateModelClient(model))
  }

  sections.push(generateMainClient(dmmf.datamodel.models))

  return sections.join('\n\n') + '\n'
}

