import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import {
  generateBaseClient,
  generateCreateInput,
  generateEnumType,
  generateMainClient,
  generateModelClient,
  generateModelInterface,
  generateUpdateInput,
  generateWhereUniqueInput,
  prismaTypeToTypeScript,
} from '../template'

describe('prismaTypeToTypeScript', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Buffer'],
  ])('maps %s to %s', (prisma, ts) => {
    expect(prismaTypeToTypeScript(prisma)).toBe(ts)
  })

  test('passes through enum/composite type names unchanged', () => {
    expect(prismaTypeToTypeScript('Role')).toBe('Role')
    expect(prismaTypeToTypeScript('Address')).toBe('Address')
  })
})

// ---------------------------------------------------------------------------
// Helpers to build minimal DMMF field/model fixtures
// ---------------------------------------------------------------------------

function field(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function model(name: string, fields: DMMF.Field[], extra?: Partial<DMMF.Model>): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...extra,
  }
}

// ---------------------------------------------------------------------------
// Enum generation
// ---------------------------------------------------------------------------

describe('generateEnumType', () => {
  test('produces a TypeScript enum', () => {
    const enumDef: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'ADMIN', dbName: null },
        { name: 'USER', dbName: null },
      ],
    }
    const result = generateEnumType(enumDef)
    expect(result).toContain("export enum Role {")
    expect(result).toContain("ADMIN = 'ADMIN'")
    expect(result).toContain("USER = 'USER'")
  })
})

// ---------------------------------------------------------------------------
// Model interface generation
// ---------------------------------------------------------------------------

describe('generateModelInterface', () => {
  test('includes scalar fields with correct types', () => {
    const m = model('User', [
      field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      field({ name: 'email', type: 'String' }),
      field({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generateModelInterface(m)
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
  })

  test('handles list fields', () => {
    const m = model('Post', [
      field({ name: 'tags', type: 'String', isList: true }),
    ])
    const result = generateModelInterface(m)
    expect(result).toContain('tags: string[]')
  })

  test('handles enum fields', () => {
    const m = model('User', [
      field({ name: 'role', type: 'Role', kind: 'enum' }),
    ])
    const result = generateModelInterface(m)
    expect(result).toContain('role: Role')
  })

  test('excludes relation fields', () => {
    const m = model('Post', [
      field({ name: 'id', type: 'Int', isId: true }),
      field({ name: 'author', type: 'User', kind: 'object' }),
      field({ name: 'authorId', type: 'Int', isReadOnly: true }),
    ])
    const result = generateModelInterface(m)
    expect(result).toContain('id: number')
    expect(result).toContain('authorId: number')
    expect(result).not.toContain('author: User')
  })
})

// ---------------------------------------------------------------------------
// CreateInput generation
// ---------------------------------------------------------------------------

describe('generateCreateInput', () => {
  test('makes fields with defaults optional', () => {
    const m = model('User', [
      field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      field({ name: 'email', type: 'String' }),
      field({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
    ])
    const result = generateCreateInput(m)
    expect(result).toContain('id?: number')
    expect(result).toContain('createdAt?: Date')
    expect(result).toMatch(/email: string/) // required — no ?
    expect(result).not.toMatch(/email\?/)
  })

  test('makes nullable fields optional', () => {
    const m = model('User', [
      field({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generateCreateInput(m)
    expect(result).toContain('name?: string | null')
  })

  test('makes updatedAt fields optional', () => {
    const m = model('User', [
      field({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
    ])
    const result = generateCreateInput(m)
    expect(result).toContain('updatedAt?: Date')
  })

  test('makes readOnly fields optional', () => {
    const m = model('Post', [
      field({ name: 'authorId', type: 'Int', isReadOnly: true }),
    ])
    const result = generateCreateInput(m)
    expect(result).toContain('authorId?: number')
  })
})

// ---------------------------------------------------------------------------
// UpdateInput generation
// ---------------------------------------------------------------------------

describe('generateUpdateInput', () => {
  test('makes all fields optional and excludes id/readOnly', () => {
    const m = model('User', [
      field({ name: 'id', type: 'Int', isId: true }),
      field({ name: 'email', type: 'String' }),
      field({ name: 'authorId', type: 'Int', isReadOnly: true }),
    ])
    const result = generateUpdateInput(m)
    expect(result).toContain('email?: string')
    expect(result).not.toContain('id')
    expect(result).not.toContain('authorId')
  })
})

// ---------------------------------------------------------------------------
// WhereUniqueInput generation
// ---------------------------------------------------------------------------

describe('generateWhereUniqueInput', () => {
  test('uses @id field', () => {
    const m = model('User', [
      field({ name: 'id', type: 'Int', isId: true }),
      field({ name: 'email', type: 'String' }),
    ])
    const result = generateWhereUniqueInput(m)
    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('id: number')
    expect(result).not.toContain('email')
  })

  test('uses compound @@id', () => {
    const m = model(
      'PostTag',
      [
        field({ name: 'postId', type: 'Int' }),
        field({ name: 'tagId', type: 'Int' }),
      ],
      { primaryKey: { name: null, fields: ['postId', 'tagId'] } },
    )
    const result = generateWhereUniqueInput(m)
    expect(result).toContain('postId: number')
    expect(result).toContain('tagId: number')
  })

  test('falls back to @unique field', () => {
    const m = model('Session', [
      field({ name: 'token', type: 'String', isUnique: true }),
      field({ name: 'data', type: 'String' }),
    ])
    const result = generateWhereUniqueInput(m)
    expect(result).toContain('token: string')
    expect(result).not.toContain('data')
  })
})

// ---------------------------------------------------------------------------
// Client classes generation
// ---------------------------------------------------------------------------

describe('generateBaseClient', () => {
  test('produces a class with request method', () => {
    const result = generateBaseClient()
    expect(result).toContain('class BaseRestClient')
    expect(result).toContain('protected async request<T>')
    expect(result).toContain('fetch(url')
  })
})

describe('generateModelClient', () => {
  test('produces CRUD methods for a model', () => {
    const m = model('User', [
      field({ name: 'id', type: 'Int', isId: true }),
      field({ name: 'email', type: 'String' }),
    ])
    const result = generateModelClient(m)
    expect(result).toContain('export class UserClient extends BaseRestClient')
    expect(result).toContain('async findMany(): Promise<User[]>')
    expect(result).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User>')
    expect(result).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(result).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(result).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')
  })

  test('uses model id field in URL paths', () => {
    const m = model('Post', [
      field({ name: 'postId', type: 'String', isId: true }),
    ])
    const result = generateModelClient(m)
    expect(result).toContain('where.postId')
    expect(result).toContain("'/post'")
  })
})

describe('generateMainClient', () => {
  test('aggregates model clients with camelCase property names', () => {
    const models = [
      model('User', [field({ name: 'id', type: 'Int', isId: true })]),
      model('BlogPost', [field({ name: 'id', type: 'Int', isId: true })]),
    ]
    const result = generateMainClient(models)
    expect(result).toContain('export class RestClient')
    expect(result).toContain('user: UserClient')
    expect(result).toContain('blogPost: BlogPostClient')
    expect(result).toContain('this.user = new UserClient(baseUrl)')
    expect(result).toContain('this.blogPost = new BlogPostClient(baseUrl)')
  })
})

