import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../generator'

function minimalDmmf(overrides?: Partial<DMMF.Datamodel>): DMMF.Document {
  return {
    datamodel: {
      models: [],
      enums: [],
      types: [],
      indexes: [],
      ...overrides,
    },
    schema: {
      inputObjectTypes: {},
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function field(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function model(name: string, fields: DMMF.Field[], extra?: Partial<DMMF.Model>): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
    ...extra,
  }
}

describe('generateRestClient', () => {
  test('generates header comment for empty schema', () => {
    const result = generateRestClient(minimalDmmf())
    expect(result).toContain('Generated by prisma-generator-rest-client')
    expect(result).toContain('DO NOT EDIT')
  })

  test('generates base and main client for empty schema', () => {
    const result = generateRestClient(minimalDmmf())
    expect(result).toContain('class BaseRestClient')
    expect(result).toContain('export class RestClient')
  })

  test('generates enum types', () => {
    const dmmf = minimalDmmf({
      enums: [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
    })
    const result = generateRestClient(dmmf)
    expect(result).toContain('export enum Role')
  })

  test('generates complete output for a single model', () => {
    const dmmf = minimalDmmf({
      models: [
        model('User', [
          field({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
          field({ name: 'email', type: 'String', isUnique: true }),
          field({ name: 'name', type: 'String', isRequired: false }),
          field({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
        ]),
      ],
    })

    const result = generateRestClient(dmmf)

    // Interface
    expect(result).toContain('export interface User {')
    expect(result).toContain('id: number')
    expect(result).toContain('email: string')
    expect(result).toContain('name: string | null')
    expect(result).toContain('createdAt: Date')

    // CreateInput — id and createdAt optional (defaults), name optional (nullable)
    expect(result).toContain('export interface UserCreateInput {')
    expect(result).toMatch(/id\?: number/)
    expect(result).toMatch(/createdAt\?: Date/)
    expect(result).toMatch(/name\?: string \| null/)

    // UpdateInput — no id
    expect(result).toContain('export interface UserUpdateInput {')

    // WhereUniqueInput
    expect(result).toContain('export interface UserWhereUniqueInput {')

    // Model client
    expect(result).toContain('export class UserClient extends BaseRestClient')
    expect(result).toContain('async findMany(): Promise<User[]>')
    expect(result).toContain('async findUnique(where: UserWhereUniqueInput): Promise<User>')
    expect(result).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(result).toContain('async update(where: UserWhereUniqueInput, data: UserUpdateInput): Promise<User>')
    expect(result).toContain('async delete(where: UserWhereUniqueInput): Promise<User>')

    // Main client
    expect(result).toContain('user: UserClient')
  })

  test('generates output for multiple models', () => {
    const dmmf = minimalDmmf({
      models: [
        model('User', [
          field({ name: 'id', type: 'Int', isId: true }),
          field({ name: 'email', type: 'String' }),
        ]),
        model('Post', [
          field({ name: 'id', type: 'Int', isId: true }),
          field({ name: 'title', type: 'String' }),
          field({ name: 'authorId', type: 'Int', isReadOnly: true }),
        ]),
      ],
    })

    const result = generateRestClient(dmmf)

    expect(result).toContain('export interface User {')
    expect(result).toContain('export interface Post {')
    expect(result).toContain('export class UserClient extends BaseRestClient')
    expect(result).toContain('export class PostClient extends BaseRestClient')
    expect(result).toContain('user: UserClient')
    expect(result).toContain('post: PostClient')
  })

  test('generates output with enums and models together', () => {
    const dmmf = minimalDmmf({
      enums: [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
      models: [
        model('User', [
          field({ name: 'id', type: 'Int', isId: true }),
          field({ name: 'role', type: 'Role', kind: 'enum' }),
        ]),
      ],
    })

    const result = generateRestClient(dmmf)
    expect(result).toContain('export enum Role')
    expect(result).toContain('role: Role')
  })

  test('skips relation (object) fields', () => {
    const dmmf = minimalDmmf({
      models: [
        model('Post', [
          field({ name: 'id', type: 'Int', isId: true }),
          field({ name: 'title', type: 'String' }),
          field({ name: 'author', type: 'User', kind: 'object' }),
        ]),
      ],
    })

    const result = generateRestClient(dmmf)
